        min_total_cost = Math.min(min_total_cost, cost_not_using_0);
    } else if (n === 1 && k === 1) {
        // n=1 case is impossible based on constraints (n>=2), but for completeness:
        min_total_cost = 0; // Trivial case if it were allowed
    }


    // Case 2: Index 0 IS a peak.
    // If index 0 is chosen, indices 1 and n-1 cannot be chosen.
    if (k >= 1) {
        // We need to select K-1 peaks from indices 2 to n-2 (length n-3).
        if (n - 3 >= 0) {
