fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    val K = k.toInt()

    // Theoretical maximum number of peaks is floor(n / 2).
    if (K > n / 2) {
        return -1L
    }

    // 1. Calculate the cost C_i for every index i to be a peak, assuming neighbors are fixed.
    val costs = LongArray(n)
    for (i in 0 until n) {
        val prev = (i - 1 + n) % n
        val next = (i + 1) % n

        // Required value for nums[i] to be a peak: max(nums[prev], nums[next]) + 1
        val required = kotlin.math.max(nums[prev], nums[next]) + 1

        // Cost is the increase needed
        costs[i] = kotlin.math.max(0, required - nums[i])
    }

    // Helper function for finding minimum cost to select exactly K non-adjacent items in a line of length L
    // C is the cost array for the L elements.
    fun solveLinear(L: Int, K_target: Int, C: LongArray): Long {
        if (K_target < 0) return Long.MAX_VALUE
        if (K_target == 0) return 0L
        if (L < 2 * K_target - 1) return Long.MAX_VALUE // Necessary condition: L >= 2K - 1 for K non-adjacent elements

        // dp[i][j][state]: min cost considering elements 0..i-1, having chosen j peaks,
        // where state=1 means element i-1 was chosen, state=0 means it was not.
        // Size: (L+1) x (K_target+1) x 2
        val dp = Array(L + 1) { 
            Array(K_target + 1) { 
                LongArray(2) { Long.MAX_VALUE } 
            } 
        }

        // Base Case: Before element 0 (i=0)
        dp[0][0][0] = 0L

        for (i in 1..L) {
            val cost_i_minus_1 = C[i - 1]

            // Case j=0: 0 peaks selected so far
            dp[i][0][0] = 0L
            // dp[i][0][1] remains Long.MAX_VALUE (cannot select item i-1 if j=0)

            for (j in 1..K_target) {
                // Current item (i-1) NOT selected (state=0)
                // Transition from either state of i-2
                dp[i][j][0] = kotlin.math.min(
                    dp[i - 1][j][0], 
                    dp[i - 1][j][1]
                )

                // Current item (i-1) IS selected (state=1)
                // Must transition from state 0 at i-2 (i.e., dp[i-1][j-1][0])
                if (j >= 1) {
                    val prevCost = dp[i - 1][j - 1][0]
                    if (prevCost != Long.MAX_VALUE) {
                         dp[i][j][1] = prevCost + cost_i_minus_1
                    }
                }
            }
        }

        // Result: Min cost to select exactly K_target peaks in the line of length L
        return kotlin.math.min(dp[L][K_target][0], dp[L][K_target][1])
    }

    var minTotalCost = Long.MAX_VALUE

    // --- Case 1: Index 0 is NOT a peak ---
    // Solve linear problem for indices 1 to n-1 (length n-1), target K peaks.
    if (n > 1) {
        val costsLinear = LongArray(n - 1) { costs[it + 1] } // Costs for indices 1 to n-1
        val costNotUsing0 = solveLinear(n - 1, K, costsLinear)
        minTotalCost = kotlin.math.min(minTotalCost, costNotUsing0)
    } else if (n == 1 && K == 0) {
        minTotalCost = 0L
    }

    // --- Case 2: Index 0 IS a peak ---
    if (K >= 1) {
        // If index 0 is chosen, indices 1 and n-1 cannot be chosen.
        // We need K-1 peaks from indices 2 to n-2 (length n-3).
        if (n - 3 >= 0) {
            val costsLinear = if (n - 3 > 0) {
                LongArray(n - 3) { costs[it + 2] } // Costs for indices 2 to n-2
            } else {
                LongArray(0)
            }

            val requiredK = K - 1

            // Check feasibility for the remaining linear segment
            if (requiredK <= (n - 3) / 2) {
                val costRemaining = solveLinear(n - 3, requiredK, costsLinear)
                if (costRemaining != Long.MAX_VALUE) {
                    val totalCost = costs[0] + costRemaining
                    minTotalCost = kotlin.math.min(minTotalCost, totalCost)
                }
            }
        } else if (n == 2 && K == 1) {
            // N=2: Indices 0, 1. If 0 is peak, 1 cannot be. K-1 = 0.
            minTotalCost = kotlin.math.min(minTotalCost, costs[0])
        } else if (n == 3 && K == 1) {
            // N=3: Indices 0, 1, 2. If 0 is peak, 1 and 2 cannot be. K-1 = 0.
            minTotalCost = kotlin.math.min(minTotalCost, costs[0])
        }
    }

    return if (minTotalCost == Long.MAX_VALUE) -1L else minTotalCost
}
