    // but here we want to find a minimum cost independent set of size $k$.

    // --- Solving Minimum Weight Independent Set of Size K on a Cycle ---

    // 1. Calculate the cost $C_i$ for every index $i$ to be a peak, assuming neighbors are fixed.
    const costs = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        const prev = (i - 1 + n) % n;
        const next = (i + 1) % n;

        // Required value for nums[i] to be a peak: max(nums[prev], nums[next]) + 1
        const required = Math.max(nums[prev], nums[next]) + 1;

        // Cost is the increase needed
        costs[i] = Math.max(0, required - nums[i]);
    }

    // 2. Use DP for finding the minimum cost to select $k$ non-adjacent items in a line.
    // DP State: dp[i][j][state]
    // i: current index being considered (0 to n-1)
    // j: number of peaks selected so far (0 to k)
    // state: 0 if nums[i] is NOT selected, 1 if nums[i] IS selected.

    // Since we have a cycle, we break it by fixing the state of index 0 (and n-1).

    // Helper function for linear arrangement (0 to L-1)
    function solveLinear(L, K, C) {
        // dp[i][j][state]: min cost considering elements 0..i-1, having chosen j peaks,
        // where state=1 means element i-1 was chosen, state=0 means it was not.
        // Size: (L+1) x (K+1) x 2
        const dp = Array(L + 1).fill(0).map(() => 
            Array(K + 1).fill(0).map(() => [Infinity, Infinity])
        );

        // Base Case: Before element 0 (i=0)
        dp[0][0][0] = 0; // 0 items chosen, 0 cost, previous was not chosen (vacuously true)

        for (let i = 1; i <= L; i++) {
            const cost_i_minus_1 = C[i - 1];

            // Case j=0: 0 peaks selected so far
            dp[i][0][0] = 0; // Always 0 cost if no peaks selected
            dp[i][0][1] = Infinity; // Cannot select item i-1 if j=0

            for (let j = 1; j <= K; j++) {
                // Current item (i-1) NOT selected (state=0)
                // We can transition from either state of i-2
                dp[i][j][0] = Math.min(
                    dp[i - 1][j][0], 
                    dp[i - 1][j][1]
                );

                // Current item (i-1) IS selected (state=1)
                // Must transition from state 0 at i-2 (i.e., dp[i-1][j-1][0])
                if (j >= 1) {
                    dp[i][j][1] = dp[i - 1][j - 1][0] + cost_i_minus_1;
                }
            }
        }

        // Result: Min cost to select exactly K peaks in the line of length L
        return Math.min(dp[L][K][0], dp[L][K][1]);
    }

    let min_total_cost = Infinity;

    // 3. Handle Circularity by fixing the state of index 0.

    // Case 1: Index 0 is NOT a peak.
    // We solve the linear problem for indices 1 to n-1 (length n-1), target K peaks.
    if (n > 1) {
        const costs_linear = costs.slice(1); // Costs for indices 1 to n-1
        const cost_not_using_0 = solveLinear(n - 1, k, costs_linear);
        min_total_cost = Math.min(min_total_cost, cost_not_using_0);
    } else if (n === 1 && k === 1) {
        // n=1 case is impossible based on constraints (n>=2), but for completeness:
        min_total_cost = 0; // Trivial case if it were allowed
    }


    // Case 2: Index 0 IS a peak.
    // If index 0 is chosen, indices 1 and n-1 cannot be chosen.
    if (k >= 1) {
        // We need to select K-1 peaks from indices 2 to n-2 (length n-3).
        if (n - 3 >= 0) {
            const costs_linear = costs.slice(2, n - 1); // Costs for indices 2 to n-2
            const required_k = k - 1;

            if (required_k <= Math.floor((n - 3) / 2)) {
                 const cost_remaining = solveLinear(n - 3, required_k, costs_linear);
                 const total_cost = costs[0] + cost_remaining;
                 min_total_cost = Math.min(min_total_cost, total_cost);
            }
        } else if (n === 2 && k === 1) {
            // N=2: Indices 0, 1. If 0 is peak, 1 cannot be. K-1 = 0.
            // Linear length is 0. solveLinear(0, 0, []) = 0.
            // Total cost = costs[0] + 0.
            min_total_cost = Math.min(min_total_cost, costs[0]);
        } else if (n === 3 && k === 1) {
             // N=3: Indices 0, 1, 2. If 0 is peak, 1 and 2 cannot be. K-1 = 0.
             // Linear length is 0. solveLinear(0, 0, []) = 0.
             // Total cost = costs[0] + 0.
             min_total_cost = Math.min(min_total_cost, costs[0]);
        }
    }

    if (min_total_cost === Infinity) {
        return -1;
    }
    return min_total_cost;
}
